package github.chains;

import spoon.reflect.factory.Factory;
import spoon.reflect.factory.FactoryImpl;
import spoon.support.DefaultCoreFactory;
import spoon.support.StandardEnvironment;
import spoon.compiler.SpoonResourceHelper;
import spoon.reflect.declaration.CtImport;
import spoon.reflect.declaration.CtPackage;
import spoon.reflect.declaration.CtType;
import spoon.reflect.visitor.filter.TypeFilter;
import spoon.reflect.visitor.chain.CtScannerListener;
import spoon.reflect.visitor.chain.ScanningMode;
import spoon.reflect.code.CtImportReference;
import spoon.reflect.reference.CtTypeReference;

import java.io.File;
import java.util.List;

public class Main {
    public static void main(String[] args) {
        // Check if the correct number of arguments are provided
        if (args.length < 1) {
            System.err.println("Usage: java Main <source_directory>");
            System.exit(1);
        }

        String sourceDirectory = args[0];

        // Create Spoon factory
        Factory factory = new FactoryImpl(new DefaultCoreFactory(), new StandardEnvironment());

        // Process the source directory
        try {
            factory.getEnvironment().setComplianceLevel(11);
            factory.getEnvironment().setSourceOutputDirectory(new File(sourceDirectory));

            // Add the source directory to the factory
            factory.addInputResource(SpoonResourceHelper.createResource(new File(sourceDirectory)));

            // Process all files
            factory.buildModel();

            // Apply transformation
            applyTransformations(factory);

            // Print modified files
            System.out.println("Transformation completed successfully.");
        } catch (Exception e) {
            System.err.println("Error processing files: " + e.getMessage());
            e.printStackTrace();
        }
    }

    private static void applyTransformations(Factory factory) {
        // Find all import statements in the model
        List<CtImport> imports = factory.getModel().getElements(new TypeFilter<>(CtImport.class));

        // Transform javax to jakarta imports
        for (CtImport ctImport : imports) {
            if (ctImport.getReference() != null) {
                CtTypeReference<?> importedType = ctImport.getReference();
                String qualifiedName = importedType.getQualifiedName();

                // Check if this is a javax import that needs to be converted to jakarta
                if (qualifiedName.startsWith("javax.")) {
                    // Create the new jakarta qualified name
                    String jakartaQualifiedName = qualifiedName.replaceFirst("javax\\.", "jakarta\\.");

                    // Replace the import
                    CtTypeReference<?> newReference = factory.Type().createReference(jakartaQualifiedName);
                    ctImport.setReference(newReference);

                    System.out.println("Transformed import: " + qualifiedName + " -> " + jakartaQualifiedName);
                }
            }
        }
    }
}

