package github.chains;

import spoon.Launcher;
import spoon.reflect.CtModel;
import spoon.reflect.declaration.CtImport;
import spoon.reflect.visitor.filter.TypeFilter;

import java.util.List;

public class Main {
    public static void main(String[] args) {
        // Check if the correct number of arguments are provided
        if (args.length < 1) {
            System.err.println("Usage: java Main <source_directory>");
            System.exit(1);
        }

        String sourceDirectory = args[0];

        // Create Spoon launcher
        Launcher launcher = new Launcher();
        launcher.getEnvironment().setComplianceLevel(11);

        // Add the source directory to the launcher
        launcher.addInputResource(sourceDirectory);

        // Process all files
        CtModel model = launcher.buildModel();

        // Find all import statements in the model
        List<CtImport> imports = model.getElements(new TypeFilter<>(CtImport.class));

        // Transform javax to jakarta imports
        int transformedCount = 0;
        for (CtImport ctImport : imports) {
            String importReference = ctImport.getReference().toString();

            // Check if this is a javax import that needs to be converted to jakarta
            if (importReference.startsWith("javax.")) {
                // Create the new jakarta qualified name
                String jakartaReference = importReference.replaceFirst("javax\\.", "jakarta\\.");

                // Replace the import
                ctImport.setReference(jakartaReference);

                System.out.println("Transformed import: " + importReference + " -> " + jakartaReference);
                transformedCount++;
            }
        }

        System.out.println("Transformation completed. " + transformedCount + " imports were transformed.");

        // Print the modified model to verify
        launcher.setSourceOutputDirectory(sourceDirectory);
        launcher.process();
    }
}

